var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"이게…… 우리들의 첫 게임…… 카운터즈 사가……?","JPN":"これが……僕たちの初のゲーム……カウンターズ・サーガ……？","ENG":"This is... our first game...! Counters Saga...","TWN":"這是……我們的第一個遊戲…… 制裁者傳奇……？"},"stage":{"bg":"GAMECIRCLE_02","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"오호!? 쌔삥이라 따끈따근한데? 이 정도면 진짜로 대박 칠 거 같지 않나?","JPN":"おお！？　出来立てほやほややん！　これならホンマに大ヒットしそうやな？","ENG":"Aha! Hot off the press! This is going to be a show stopper for sure!","TWN":"哇喔！？是剛做好的嗎？還熱熱的呢？這應該會大賣吧？"},"stage":{"bg":"GAMECIRCLE_02","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"응응, 너무 귀엽게 나온 거 같아. 역시 박스 군은 대단해!","JPN":"うんうん、とてもかわいくできたと思う。やっぱりダンボール君はすごい！","ENG":"Yes, it’s so cute! You’re awesome, Boxie!","TWN":"嗯嗯，超可愛的，紙箱小朋友真的好厲害！"},"stage":{"bg":"GAMECIRCLE_02","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"하하, 아니에요.","JPN":"はは、とんでもないです。","ENG":"Ha ha, thanks.","TWN":"哈哈，沒有啦。"},"stage":{"bg":"GAMECIRCLE_02","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"SD 캐릭터는 자신 없었는데…… 그래도 실제로 프린팅된 걸 보니까 그럭저럭 잘 나온 것 같아서 기뻐요.","JPN":"SDキャラは自信なかったんですけど……でも実際にプリントされたのを見ると、まあまあの出来なので嬉しいです。","ENG":"I’m not too confident with SD art styles... But looking at how it got printed out, I guess it’s okay.","TWN":"SD角色我沒什麼把握……不過看到實際呈現後，成果很不錯呢，真開心。"},"stage":{"bg":"GAMECIRCLE_02","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"뭐라노? 아무나 이렇게 못 그린다 안 하나. 이건 니만 할 수 있는 거라고.","JPN":"何言ってんねん。普通はこうは描けへんて。これはあんたにしかできへんよ。","ENG":"What's that ya say? It ain’t common bein’ able to draw like Picasso! That's somethin’ only you can do, kiddo.","TWN":"說啥呢？這可不是誰都畫得出來的，只有你可以。"},"stage":{"bg":"GAMECIRCLE_02","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"니는 좀 더 자신감을 가져도 된다! 마, 가슴도 좀 더 쫙 펴고!","JPN":"あんたはもっと自信持ちいや！　ほら、もっと胸張って！","ENG":"Whatcha need is some self-respect! Keep your chin up!","TWN":"你要對自己更有自信！抬頭挺胸！"},"stage":{"bg":"GAMECIRCLE_02","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"아, 그럼 우리 타임 캡슐을 만들어 보는 거 어때?","JPN":"あ、じゃあタイムカプセルを作ってみるのはどう？","ENG":"Hey, why don’t we make a time capsule?","TWN":"這樣吧！不如做個時空膠囊怎麼樣？"},"stage":{"bg":"GAMECIRCLE_02","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"오오, 좋네! 나중에 어른이 되면 다 같이 모여가 열어보는기다! 약속이래이!","JPN":"おお、ええやん！　後で大人になったら、みんな集まって開けてみよ！　約束やで！","ENG":"Oh goodie! Y’all are goin’ to gather after we’ve grown up, and we’re gonna open this together! It’s a promise!","TWN":"喔喔，不錯喔！等長大後再一起打開來看！說好囉！"},"stage":{"bg":"GAMECIRCLE_02","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"……저도 좋아요.","JPN":"……僕も賛成です。","ENG":"...Cool with me as well.","TWN":"……我也同意。"},"stage":{"bg":"GAMECIRCLE_02","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DOG_NPC_GAMECIRCLE_NULL","text":{"KOREA":"멍! 멍!","JPN":"ワン！　ワン！","ENG":"Woof! Woof!","TWN":"汪汪！"},"stage":{"bg":"GAMECIRCLE_02","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_DOG_VOICE"},{"id":"L14_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GAMECIRCLE_02","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"얘들아……. 미안한데.","JPN":"みんな……聞いて。","ENG":"Guys... I’m really sorry, but...","TWN":"大家……不好意思，"},"stage":{"bg":"GAMECIRCLE_02","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"문제가 생겼어…… 중대한 문제.","JPN":"問題が起きた……重大な問題。","ENG":"We have a problem... A big problem.","TWN":"發生……大問題。"},"stage":{"bg":"GAMECIRCLE_02","bgm":"OFFICE_COMMON_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"뭐꼬? 와 그리 심각한 표정인데? 무섭게시리.","JPN":"何や？　なんでそんな深刻な顔してるん。怖いやん。","ENG":"What is it? Why so serious? Ya scarin’ me.","TWN":"怎麼啦？幹啥這麼嚴肅？你別嚇我們。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"쌓여있잖아.","JPN":"積まれてる。","ENG":"It’s stacked up high.","TWN":"堆好多，"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"상자…… 저길 봐.","JPN":"箱……あれ見て。","ENG":"The boxes... look.","TWN":"紙箱……你們看。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"자, 잠깐!? 연구실 앞에 상자가 엄청 많이 있잖아?","JPN":"え、なに！？　部室の前に箱があんなにたくさん？","ENG":"W-wait! There are way too many boxes over there!","TWN":"怎…怎麼會！？研究室前面堆好多紙箱。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L24_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"이 한 상자뿐이야…… 초도 물량 200장…… 원래 우리가 시킨 건.","JPN":"この一箱だけ……初刷200枚……もともと私たちが注文したの。","ENG":"200 CD discs... one box... was our primary... order....","TWN":"假設一箱……有200片……那我們下單的數量。"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"그, 그럼…… 그 상자가 10개가 쌓여있다는 말은……!?","JPN":"じゃ、じゃあ……その箱が10箱分積まれてるってことは……！？","ENG":"T-that means... Since there are 10 boxes stacked up...","TWN":"也…也就是……那邊有10個紙箱……就表示有！？"},"stage":{"bg":"CIRCLEROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"2000개.","JPN":"2000枚。","ENG":"2000 discs.","TWN":"2000片。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"0을 하나 더 붙인 거야……. 발주할 때.","JPN":"0、一つ多くつけた……発注する時。","ENG":"Typed in an extra zero... when ordering... we did.","TWN":"下單時多按一個0……應該是。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"뭐, 뭐라고요!? 이거 발주한 사람이 누군데요!?","JPN":"な、なんですって！？　これ、誰が発注したんですか！？","ENG":"W-what?! Who was in charge of placing the order?!","TWN":"什…什麼！？是誰負責下單的！？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"아, 아하하하……","JPN":"あ、あははは……","ENG":"A-ah, ah ha ha ha...","TWN":"哈，哈哈哈哈……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"미안타. 그거…… 아마 내가 시킨 것 같은데…….","JPN":"ごめん。それ……たぶんウチや……","ENG":"That’ll be me... Sorry.","TWN":"抱歉…兇手好像是我……"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"또 미리네 누나에요!?","JPN":"またマリさんですか！？","ENG":"You again, Rinae?!","TWN":"又是你！？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"마! 또라니! 박스 니 와 그렇게 말을 섭섭하게 하는데?","JPN":"ちょっと！　またって！　ダンボール、あんたその口調はなんなんや！","ENG":"What do you mean by that?! Why ya bein’ mean to me, Box?","TWN":"喂！什麼又！你怎麼這樣講話？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L38_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"괘, 괘안타! 까짓거 몽땅 팔아뿌면 되는 거 아이가! 우리 겜이라믄 완판 가능하제! 암!","JPN":"だ、大丈夫やって！　全部売っちゃえばええやん！　このゲームなら、完売できるで！　うん！","ENG":"I-It’ll be all right! It ain’t a biggie at all! Our game will be out of stock in no time! Heh!","TWN":"沒…沒事啦！反正全部賣掉就好啦！我們的遊戲沒問題啦！哼！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L41_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"하하, 과연 가능할까 2000장……?","JPN":"はは、本当にできるのかな？　2000枚……","ENG":"Ha ha, I wonder if it’ll be possible to sell out all 2000 discs...","TWN":"哈哈，真的沒問題嗎？2000片欸……？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"코미페에 온 사람들이 한 장씩 다 사주면 어떻게든 팔 수 있지 않을까요?","JPN":"コミフェに来た人が一枚ずつ買ってくれたら、なんとか売れるんじゃないでしょうか？","ENG":"If every attendee at Comic Festival purchases a disc each, it might be possible.","TWN":"來動漫展的人一人買一片的話，那應該是賣得完吧？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그, 그럼 홍보가 중요한기다! 홍보!","JPN":"そ、そうやで！　宣伝が重要や！　宣伝！","ENG":"T-then we gotta go all in on promotin’ our work! Yeah, promotion’s what we need!","TWN":"沒…沒錯！那宣傳就很重要唄！要好好宣傳！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L47_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그렇지! 게임 홍보로 우리 부스에서 코스프레 같은 걸 해보는 거다!","JPN":"そうや！　ゲームの宣伝に、ウチのブースでコスプレとかをしてみようや！","ENG":"Ya know what? We should cosplay as our characters, as a part of our promotion!","TWN":"這樣唄！在我們的攤位Cosplay宣傳遊戲唄！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L48_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"우리 게임 일러스트도 예쁘니까 분명 반응 좋을끼다!","JPN":"ゲームイラストもキレイなんだから、きっと反応ええと思う！","ENG":"It’ll be great, our illustrations are fire!","TWN":"我們遊戲的立繪這麼美，大家的反應應該會很熱烈唄！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"하고 있잖아…… 코스프레.","JPN":"もうやってる……コスプレ。","ENG":"Doing it already... cosplay.","TWN":"不是已經在……Cosplay？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"으, 으응? 뭐라고?","JPN":"え、ええ？　何やて？","ENG":"H-huh? What was that?","TWN":"啥？啥意思？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"똑같잖아……? 너랑…… 게임 속 너랑.","JPN":"一緒でしょ……マリと……ゲームの中のマリ。","ENG":"Aren’t you...? Mi Rinae... and you’re the same.","TWN":"一模一樣……你……和遊戲裡的你。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그러니까 하고 있는 거지……. 코스프레.","JPN":"だからもうやってる……コスプレ。","ENG":"So you’re doing it.... the cosplay... already.","TWN":"這不就是…… Cosplay？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"숨쉬듯이.","JPN":"自然に。","ENG":"Easy as pie.","TWN":"不費吹灰之力。"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"뭔소리고! 내가 갸를 따라하는게 아니라 갸가 내를 따라하는거제!","JPN":"何言うてんねん！　ウチがあいつをマネしてるんやなくて、あいつがウチをマネしてるんや！","ENG":"No ma’am, it ain’t! She was made after me! I ain’t mimickin’ her!","TWN":"胡說啥呢！不是我在模仿她，是她在模仿我好唄！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"자, 잠깐만……!?","JPN":"ちょ、ちょっと待って……！？","ENG":"W-wait!","TWN":"等…等等……！？"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그거다!! 내 좋은 생각이 있다!","JPN":"それや！！　ウチ、いいアイデア思いついたで！","ENG":"That’s it! I have a good idea!","TWN":"就是那個！我想到很棒的點子！"},"stage":{"bg":"CIRCLEROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"하아아아압!","JPN":"はああああっ！","ENG":"Haaaah!","TWN":"哈啊啊啊啊！"},"stage":{"bg":"COMICFESTIVAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L17_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"스타라이트 스페샬이다 안 하나!","JPN":"スターライト・スペシャルや！","ENG":"It’s Starlight Special, ya hear?!","TWN":"就是星光特技！"},"stage":{"bg":"COMICFESTIVAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_HYPER_ATTACK_START"},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"뭐하는 거야? 이 부스는 왜 이렇게 사람이 몰려 있어?","JPN":"何してるんだ？　このブース、なんでこんな人が集まってるんだ？","ENG":"What’s going on? Why is this booth so crowded?","TWN":"怎麼回事？怎麼這麼多人擠在那個攤位？"},"stage":{"bg":"COMICFESTIVAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"저기 봐, 무슨 코스프레 촬영 같은 걸 하는데 저 여자애 동작이 거의 서커스 묘기 수준이야!","JPN":"あそこ見て、何かのコスプレ撮影をやってるんだけど、あの女の子、体の動きがまるでサーカスみたいだわ！","ENG":"Look! They’re holding some kind of cosplay shooting, and that girl over there is pulling circus tricks!","TWN":"你看，那邊好像在拍Cosplay，那女生的動作根本跟特技表演沒兩樣吧！"},"stage":{"bg":"COMICFESTIVAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"자기들이 만든 게임 캐릭터를 코스프레 했나 봐. 하핫, 진짜 귀여운데?","JPN":"自作ゲームのキャラのコスプレみたいだぞ。ははっ、結構かわいいじゃん！","ENG":"They must have dressed up for their own game character. Ha ha, looks pretty cute!","TWN":"她扮的好像是他們自己遊戲裡的角色，哈哈，超可愛欸？"},"stage":{"bg":"COMICFESTIVAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"손님, 그게 아니라…… 점마가 내를……","JPN":"お客さん、そうやなくて……あいつがウチを……","ENG":"It ain’t that... she’s the one who–","TWN":"這位客人，我跟你說……不是這樣的，是……"},"stage":{"bg":"COMICFESTIVAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"아하하. 맞아요! 맞아요! 저희 누나 코스프레 퀄리티가 꽤 괜찮죠?","JPN":"あはは。そうです！　そうなんです！　マリさんのコスプレ、かなりのクオリティですよね？","ENG":"Ah ha ha, you’re absolutely right! Her cosplay looks great, doesn’t she?","TWN":"哈哈哈，沒錯沒錯！我們姊姊Cosplay品質很不錯吧？"},"stage":{"bg":"COMICFESTIVAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L31_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"후후, 와서 편하게 게임 하고 가세요. 한정판 팬시도 있어요.","JPN":"ふふ、来てゆっくりゲームを楽しんでいってください。限定マスコットもありますよ。","ENG":"Fu fu, feel free to try our game. We have merch that’s limited edition.","TWN":"呵呵，歡迎進來體驗遊戲，還有限量掛飾喔。"},"stage":{"bg":"COMICFESTIVAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"사주세요…… 저희 게임.","JPN":"買ってください……私たちのゲーム。","ENG":"Buy it... our game, please.","TWN":"買一片吧……我們的遊戲。"},"stage":{"bg":"COMICFESTIVAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"한정 팬시도 귀여운데? 잠깐 부스 좀 보고 가자.","JPN":"限定マスコットもかわいいね？　ちょっとブース見ていこうよ。","ENG":"This merch looks cute! Let’s take a closer look.","TWN":"限量掛飾也很可愛欸？我們去攤位逛一下吧？"},"stage":{"bg":"COMICFESTIVAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"응, 게임도 생각보다 재밌을 거 같아.","JPN":"うん、ゲームも思ったより面白そう。","ENG":"Yeah, the game looks good as well!","TWN":"嗯，感覺遊戲應該也不錯玩。"},"stage":{"bg":"COMICFESTIVAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"미리네 누나, 이거 진짜 반응이 꽤 나쁘지 않은데요?","JPN":"マリさん、これ、本当に反応がなかなかいいですよ。","ENG":"This is going better than expected, Rinae.","TWN":"宓璃奈姊姊，大家的反應好像很不錯欸？"},"stage":{"bg":"COMICFESTIVAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L40_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그쟈? 지난번 코미페에서 내를 신기하게 보는 사람들이 꽤 있었데이.","JPN":"やろ？　前回のコミフェでウチのことを不思議そうに見てる人がめっちゃ多かったんや。","ENG":"Ain’t that right? I caught a lot of attention from ‘em folks last time.","TWN":"是不是？上次動漫展的時候就已經有很多人注意到我。"},"stage":{"bg":"COMICFESTIVAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L41_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"헤헷, 이대로만 가면 정말로 초도 물량 2000개 진짜로 완판하는 거 아이가?","JPN":"へへっ、このまま行けばホンマに初回で2000枚、完売するんちゃうん？","ENG":"Heh, I think we actually might be able to sell all 2000 discs!","TWN":"嘿嘿，這樣下去，那2000片應該真的可以賣光光唄？"},"stage":{"bg":"COMICFESTIVAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L42_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"정말이에요. 사람들이 저희 게임을 좋아해 주셔서 고생한 보람이 있는 것 같아요!","JPN":"そうですね。みんなが僕たちのゲームを好きになってくれて、苦労した甲斐がありました！","ENG":"She’s right. It’s very rewarding to see all these people trying out our game!","TWN":"真的欸！看到這麼多人喜歡我們的遊戲，就覺得辛苦都是有價值的呢！"},"stage":{"bg":"COMICFESTIVAL","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L44_1","type":"dialog","speaker":null,"text":{"KOREA":"어, 저기요? 꼬마야? 여기 이건 얼마야?","JPN":"すいません！　あ、君？　これっていくら？","ENG":"Excuse me, uh... Kid? How much is this?","TWN":"請問一下？這個多少錢？"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}},{"id":"L45_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"아, 잠시만요!","JPN":"あ、ちょっと待ってくださいね！","ENG":"Oh, just a minute!","TWN":"喔，稍等我一下！"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"……뭔가 이상해.","JPN":"……何かおかしいよ。","ENG":"...Something doesn’t feel right.","TWN":"……好像哪裡怪怪的。"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L48_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"으응, 뭐가 이상하다는 긴데?","JPN":"ううん？　何がおかしいん？","ENG":"Eh? What is?","TWN":"嗯？哪裡怪？"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"아까부터 여기 행사장이 이상할 정도로 더운 것 같아.","JPN":"さっきからこの会場、異常に暑い気がするの。","ENG":"The convention center is strangely hot.","TWN":"從剛剛開始，會場裡就熱得很不尋常。"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그야 사람들이 이렇게 북적북적하니까 더운 거 아이가?","JPN":"そりゃあ、人がこんなにおるから暑いんちゃうん？","ENG":"Ain’t that because of the heat from all this crowd?","TWN":"應該是因為大家都擠在這裡唄？"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그건…… 그렇지만 이건 뭔가 다른 느낌이…….","JPN":"それは……そうだけど、これは何か違う感じが……","ENG":"You’re not wrong... but somehow it feels different...","TWN":"話……是沒錯，但總覺得不太對勁……"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"DOG_NPC_GAMECIRCLE_NULL","text":{"KOREA":"크르르르르……!","JPN":"グルルルル……！","ENG":"Grrrrr...!","TWN":"吼吼吼吼……！"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_DOG_VOICE_07"},{"id":"L5_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"응? <color=#ffd34c>뭔가</color>가 오고 있다고……?","JPN":"うん？　<color=#ffd34c>何か</color>が来るって……？","ENG":"Huh? <color=#ffd34c>Something</color> is coming, you say...?","TWN":"嗯？<color=#ffd34c>有什麼東西</color>正往這裡來嗎……？"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"나도 느꼈어.","JPN":"私も感じた。","ENG":"I felt it too.","TWN":"我也有感覺到。"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"모이고…… 또 퇴적되고 있어…… 사람들의 부정적인 감정.","JPN":"集まって……溜まってきてる……みんなのネガティブな感情。","ENG":"The negative emotions of people... It’s accumulating...","TWN":"一直……在累積……大家的負面情緒。"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그리고…… 왜곡되고 있어.","JPN":"それに……歪んでる。","ENG":"...And getting distorted.","TWN":"而且……扭曲中。"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"비슷해……. 지난 사고들이랑.","JPN":"似てる……この前の事故と。","ENG":"The same... it is... from the past incidents.","TWN":"很像……之前的意外。"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"그, 그렇다는 건……. 침식 현상이 시작된다는 거야? 여기서?","JPN":"つ、つまり……侵食現象が始まるってこと？　ここで？","ENG":"D-does that mean... the Counterside Effect is going to take place here?","TWN":"意思是……侵蝕現象正在發生嗎？就在這裡？"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"안 돼, 그럼 여기 있는 사람들이 다칠 거야!","JPN":"ダメ、それじゃあここにいる人たちが怪我をしちゃう！","ENG":"No! People will get hurt!","TWN":"不可以，這裡的人會受傷的！"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"BORA_GAMECIRCLE_NULL_NULL","text":{"KOREA":"커지고 있어…… 점점.","JPN":"大きくなってる……どんどん。","ENG":"It’s growing... bigger and bigger.","TWN":"越來越……大。"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"다들 침착해라!","JPN":"みんな、落ち着きい！","ENG":"Hold ya hats, ladies!","TWN":"大家冷靜點！"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"다인아, 니는 쌤한테 연락부터 해라!","JPN":"タエ、あんたは先生に連絡や！","ENG":"Dain, call Teach!","TWN":"妲茵，你先通知老師！"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"여기서 전투 요원은 내밖에 없다! 초동 대처까진 가능하겠지만 혹시 모르니까 쌤의 지원을 받아야 한데이!","JPN":"ここに戦闘要員はウチだけやから！　初動対応はできるけど、もしものことがあるから先生の応援が必要や！","ENG":"I’m the only combat agent out here! I might be able to fend off some of them, but it’s best to get help from Teach!","TWN":"這裡能作戰的人只有我一個！我是能撐一陣子，但以防萬一還是需要請求老師的支援！"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DAIN_GAMECIRCLE_NULL_NULL","text":{"KOREA":"응. 알겠어!","JPN":"うん。わかった！","ENG":"Okay!","TWN":"好，我立刻通知老師！"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAIN_GAMECIRCLE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BORA_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_DOG_VOICE"},{"id":"L29_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"침식체가 나타난 뒤에는 대처해도 늦는다! 다들 망설이지 말고 퍼뜩……!","JPN":"侵食体が現れた後じゃ、どう対処しても遅いんや！　みんな、躊躇わんとはよ……！","ENG":"It’s goin’ to be too late when the C.O.s appear! We gotta act fast–","TWN":"等到侵蝕體出現後才應變會來不及！大家動作快……！"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BOX_NPC_GAMECIRCLE_X","text":{"KOREA":"누, 누나……! 갑자기 부스에서 사람들이 하나 둘 씩……!","JPN":"ま、マリさん……！　いきなりブースで人が次々と……！","ENG":"R-Rinae...! People are starting to–","TWN":"姊…姊姊……！攤位裡的人怎麼突然一個一個消……！"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L33_1","type":"dialog","speaker":"STAR_GAMECIRCLE_NULL_NULL","text":{"KOREA":"바, 박스……!?","JPN":"だ、ダンボール……！？","ENG":"B-Box...?!","TWN":"紙…紙箱……！？"},"stage":{"bg":"COMICFESTIVAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_GAMECIRCLE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BOX_NPC_GAMECIRCLE_X","face":"UNIT_SERIOUS2"}}}}]`);export{e as default};